package value

import (
	"bytes"
	"context"
	"errors"
	"fmt"
	"testing"

	genericapirequest "k8s.io/apiserver/pkg/endpoints/request"
)

// mockTransformer is a test transformer that applies simple transformations
type mockTransformer struct {
	encryptPrefix []byte
	shouldFail    bool
	failOnFrom    bool
	failOnTo      bool
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	if m.failOnFrom || m.shouldFail {
		return nil, false, fmt.Errorf("mock decrypt error")
	}
	// Remove the prefix to get original data
	if bytes.HasPrefix(data, m.encryptPrefix) {
		return bytes.TrimPrefix(data, m.encryptPrefix), false, nil
	}
	return nil, false, fmt.Errorf("data does not have expected prefix")
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	if m.failOnTo || m.shouldFail {
		return nil, fmt.Errorf("mock encrypt error")
	}
	// Add the prefix to simulate encryption
	result := make([]byte, len(m.encryptPrefix)+len(data))
	copy(result, m.encryptPrefix)
	copy(result[len(m.encryptPrefix):], data)
	return result, nil
}

// TestTransformerRoundTrip tests that data can be encrypted and then decrypted correctly
func TestTransformerRoundTrip(t *testing.T) {
	tests := []struct {
		name      string
		data      []byte
		prefix    []byte
		shouldErr bool
	}{
		{
			name:      "simple round trip",
			data:      []byte("secret data"),
			prefix:    []byte("encrypted:"),
			shouldErr: false,
		},
		{
			name:      "empty data",
			data:      []byte(""),
			prefix:    []byte("prefix:"),
			shouldErr: false,
		},
		{
			name:      "large data",
			data:      bytes.Repeat([]byte("x"), 10000),
			prefix:    []byte("enc:"),
			shouldErr: false,
		},
		{
			name:      "binary data",
			data:      []byte{0, 1, 2, 255, 254, 253},
			prefix:    []byte("bin:"),
			shouldErr: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &mockTransformer{encryptPrefix: tt.prefix}
			ctx := context.Background()

			// Encrypt
			encrypted, err := transformer.TransformToStorage(ctx, tt.data, nil)
			if err != nil {
				t.Fatalf("encryption failed: %v", err)
			}

			// Verify encrypted data has the prefix
			if !bytes.HasPrefix(encrypted, tt.prefix) {
				t.Errorf("encrypted data does not have expected prefix")
			}

			// Decrypt
			decrypted, _, err := transformer.TransformFromStorage(ctx, encrypted, nil)
			if err != nil {
				t.Fatalf("decryption failed: %v", err)
			}

			// Verify decrypted data matches original
			if !bytes.Equal(decrypted, tt.data) {
				t.Errorf("decrypted data does not match original. got: %q, want: %q", string(decrypted), string(tt.data))
			}
		})
	}
}

// TestPrefixTransformerDecoratorBehavior tests that PrefixTransformer correctly decorates a transformer
func TestPrefixTransformerDecoratorBehavior(t *testing.T) {
	tests := []struct {
		name          string
		prefix        []byte
		data          []byte
		expectedError bool
	}{
		{
			name:          "matching prefix",
			prefix:        []byte("v1:"),
			data:          []byte("v1:encrypted"),
			expectedError: false,
		},
		{
			name:          "mismatched prefix",
			prefix:        []byte("v2:"),
			data:          []byte("v1:encrypted"),
			expectedError: true,
		},
		{
			name:          "empty prefix match",
			prefix:        []byte(""),
			data:          []byte("any data"),
			expectedError: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			mockTrans := &mockTransformer{encryptPrefix: tt.prefix}
			pt := PrefixTransformer{
				Prefix:      tt.prefix,
				Transformer: mockTrans,
			}

			ctx := context.Background()
			_, _, err := pt.Transformer.TransformFromStorage(ctx, tt.data, nil)

			if (err != nil) != tt.expectedError {
				t.Errorf("unexpected error condition. got error: %v, expected error: %t", err, tt.expectedError)
			}
		})
	}
}

// TestContextInterface tests the Context interface contract
func TestContextInterface(t *testing.T) {
	tests := []struct {
		name           string
		context        Context
		expectedOutput []byte
	}{
		{
			name:           "default context with data",
			context:        DefaultContext([]byte("test data")),
			expectedOutput: []byte("test data"),
		},
		{
			name:           "default context empty",
			context:        DefaultContext([]byte("")),
			expectedOutput: []byte(""),
		},
		{
			name:           "default context with binary",
			context:        DefaultContext([]byte{0, 255, 128}),
			expectedOutput: []byte{0, 255, 128},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := tt.context.AuthenticatedData()
			if !bytes.Equal(result, tt.expectedOutput) {
				t.Errorf("AuthenticatedData returned unexpected value. got: %v, want: %v", result, tt.expectedOutput)
			}
		})
	}
}

// TestDefaultContextAuthenticatedData verifies DefaultContext properly returns authenticated data
func TestDefaultContextAuthenticatedData(t *testing.T) {
	data := []byte("authenticated data")
	ctx := DefaultContext(data)

	authData := ctx.AuthenticatedData()

	if !bytes.Equal(authData, data) {
		t.Errorf("AuthenticatedData should return the context data. got: %q, want: %q", string(authData), string(data))
	}

	// Verify it's not just a pointer reference - modifying one shouldn't affect the other
	originalAuthData := ctx.AuthenticatedData()
	data[0] = 'X'
	newAuthData := ctx.AuthenticatedData()

	if bytes.Equal(originalAuthData, newAuthData) && data[0] == 'X' {
		// This is expected - they should be the same underlying data
		t.Logf("AuthenticatedData shares the underlying array with DefaultContext (expected behavior)")
	}
}

// TestTransformerUnionWithMultiplePrefixes tests the fanout-and-select logic of NewPrefixTransformers
func TestTransformerUnionWithMultiplePrefixes(t *testing.T) {
	tests := []struct {
		name              string
		prefixTransformers []PrefixTransformer
		inputData         []byte
		shouldFail        bool
		expectedToFail    error
		expectedStale     bool
	}{
		{
			name: "first transformer matches",
			prefixTransformers: []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
				{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
			},
			inputData:      []byte("v1:secret"),
			shouldFail:     false,
			expectedStale:  false,
		},
		{
			name: "second transformer matches",
			prefixTransformers: []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
				{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
			},
			inputData:      []byte("v2:secret"),
			shouldFail:     false,
			expectedStale:  true, // Should be marked stale since it's not the first transformer
		},
		{
			name: "no transformer matches",
			prefixTransformers: []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
				{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
			},
			inputData:      []byte("v3:secret"),
			shouldFail:     true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			union := NewPrefixTransformers(fmt.Errorf("no matching transformer"), tt.prefixTransformers...)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

			result, stale, err := union.TransformFromStorage(ctx, tt.inputData, nil)

			if tt.shouldFail {
				if err == nil {
					t.Errorf("expected error but got none")
				}
			} else {
				if err != nil {
					t.Errorf("unexpected error: %v", err)
				}
				if stale != tt.expectedStale {
					t.Errorf("unexpected stale flag. got: %t, want: %t", stale, tt.expectedStale)
				}
				if len(result) == 0 && len(tt.inputData) > 0 {
					t.Errorf("expected non-empty result")
				}
			}
		})
	}
}

// TestErrorPropagationOnDecryptionFailure tests that decryption errors are properly propagated
func TestErrorPropagationOnDecryptionFailure(t *testing.T) {
	tests := []struct {
		name          string
		transformers  []PrefixTransformer
		data          []byte
		shouldFail    bool
		errorContains string
	}{
		{
			name: "single transformer fails",
			transformers: []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &mockTransformer{failOnFrom: true, encryptPrefix: []byte("v1:")}},
			},
			data:          []byte("v1:data"),
			shouldFail:    true,
			errorContains: "mock decrypt error",
		},
		{
			name: "both transformers fail",
			transformers: []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &mockTransformer{failOnFrom: true, encryptPrefix: []byte("v1:")}},
				{Prefix: []byte("v2:"), Transformer: &mockTransformer{failOnFrom: true, encryptPrefix: []byte("v2:")}},
			},
			data:       []byte("v1:data"),
			shouldFail: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			union := NewPrefixTransformers(fmt.Errorf("default error"), tt.transformers...)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

			_, _, err := union.TransformFromStorage(ctx, tt.data, nil)

			if tt.shouldFail && err == nil {
				t.Errorf("expected error but got none")
			}
			if !tt.shouldFail && err != nil {
				t.Errorf("unexpected error: %v", err)
			}
		})
	}
}

// TestErrorPropagationOnEncryptionFailure tests that encryption errors are properly propagated
func TestErrorPropagationOnEncryptionFailure(t *testing.T) {
	tests := []struct {
		name         string
		transformer  Transformer
		data         []byte
		shouldFail   bool
	}{
		{
			name:       "transformer fails to encrypt",
			transformer: &mockTransformer{failOnTo: true, encryptPrefix: []byte("v1:")},
			data:       []byte("secret"),
			shouldFail: true,
		},
		{
			name:       "transformer encrypts successfully",
			transformer: &mockTransformer{encryptPrefix: []byte("v1:")},
			data:       []byte("secret"),
			shouldFail: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx := context.Background()
			_, err := tt.transformer.TransformToStorage(ctx, tt.data, nil)

			if tt.shouldFail && err == nil {
				t.Errorf("expected error but got none")
			}
			if !tt.shouldFail && err != nil {
				t.Errorf("unexpected error: %v", err)
			}
		})
	}
}

// TestEmptyValuesHandling tests handling of empty input values
func TestEmptyValuesHandling(t *testing.T) {
	tests := []struct {
		name           string
		data           []byte
		prefix         []byte
		shouldSucceed  bool
	}{
		{
			name:          "empty data with prefix",
			data:          []byte(""),
			prefix:        []byte("prefix:"),
			shouldSucceed: true,
		},
		{
			name:          "empty prefix",
			data:          []byte("data"),
			prefix:        []byte(""),
			shouldSucceed: true,
		},
		{
			name:          "both empty",
			data:          []byte(""),
			prefix:        []byte(""),
			shouldSucceed: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &mockTransformer{encryptPrefix: tt.prefix}
			ctx := context.Background()

			encrypted, encErr := transformer.TransformToStorage(ctx, tt.data, nil)
			if encErr != nil && tt.shouldSucceed {
				t.Fatalf("encryption should succeed but failed: %v", encErr)
			}

			if encErr == nil && tt.shouldSucceed {
				decrypted, _, decErr := transformer.TransformFromStorage(ctx, encrypted, nil)
				if decErr != nil {
					t.Fatalf("decryption should succeed but failed: %v", decErr)
				}

				if !bytes.Equal(decrypted, tt.data) {
					t.Errorf("round-trip failed. got: %q, want: %q", string(decrypted), string(tt.data))
				}
			}
		})
	}
}

// TestPrefixTransformerStaleDataMarking tests that stale flag is set correctly
func TestPrefixTransformerStaleDataMarking(t *testing.T) {
	tests := []struct {
		name                 string
		matchingTransformer  int
		expectedStaleStatus  bool
		prefixCount          int
	}{
		{
			name:                 "first transformer is fresh",
			matchingTransformer:  0,
			expectedStaleStatus:  false,
			prefixCount:          3,
		},
		{
			name:                 "second transformer is stale",
			matchingTransformer:  1,
			expectedStaleStatus:  true,
			prefixCount:          3,
		},
		{
			name:                 "third transformer is stale",
			matchingTransformer:  2,
			expectedStaleStatus:  true,
			prefixCount:          3,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			prefixTransformers := []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
				{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
				{Prefix: []byte("v3:"), Transformer: &mockTransformer{encryptPrefix: []byte("v3:")}},
			}

			union := NewPrefixTransformers(fmt.Errorf("no match"), prefixTransformers...)
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

			// Use the correct prefix for the matching transformer
			testData := append(prefixTransformers[tt.matchingTransformer].Prefix, []byte("secret")...)

			_, stale, err := union.TransformFromStorage(ctx, testData, nil)
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}

			if stale != tt.expectedStaleStatus {
				t.Errorf("stale flag mismatch. got: %t, want: %t", stale, tt.expectedStaleStatus)
			}
		})
	}
}

// TestNewPrefixTransformersUsesFirstForEncryption tests that NewPrefixTransformers always uses the first transformer for encryption
func TestNewPrefixTransformersUsesFirstForEncryption(t *testing.T) {
	mockTransformer1 := &mockTransformer{encryptPrefix: []byte("new:")}
	mockTransformer2 := &mockTransformer{encryptPrefix: []byte("old:")}

	prefixTransformers := []PrefixTransformer{
		{Prefix: []byte("new:"), Transformer: mockTransformer1},
		{Prefix: []byte("old:"), Transformer: mockTransformer2},
	}

	union := NewPrefixTransformers(fmt.Errorf("no match"), prefixTransformers...)
	ctx := context.Background()

	data := []byte("test data")
	encrypted, err := union.TransformToStorage(ctx, data, nil)
	if err != nil {
		t.Fatalf("encryption failed: %v", err)
	}

	// Should use the first transformer's prefix
	if !bytes.HasPrefix(encrypted, []byte("new:")) {
		t.Errorf("encrypted data should have first transformer's prefix. got: %v", encrypted)
	}
}

// TestTransformerInterfaceImplementation tests that types correctly implement the Transformer interface
func TestTransformerInterfaceImplementation(t *testing.T) {
	tests := []struct {
		name    string
		trans   Transformer
		isValid bool
	}{
		{
			name:    "mockTransformer implements Transformer",
			trans:   &mockTransformer{encryptPrefix: []byte("v1:")},
			isValid: true,
		},
		{
			name:    "prefixTransformers implements Transformer",
			trans:   NewPrefixTransformers(fmt.Errorf("error"), PrefixTransformer{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}}),
			isValid: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var _ Transformer = tt.trans
			var _ Read = tt.trans
			var _ Write = tt.trans

			// If we got here without a compile error, the type implements the interfaces
			if !tt.isValid {
				t.Errorf("interface implementation check failed")
			}
		})
	}
}

// TestPrefixTransformerWithMultipleTransformers tests behavior with multiple prefix transformers in various configurations
func TestPrefixTransformerWithMultipleTransformers(t *testing.T) {
	tests := []struct {
		name                string
		desc                string
		setup               func() (Transformer, []byte)
		expectedToSucceed   bool
	}{
		{
			name: "happy path first",
			desc: "data with first transformer prefix decrypts successfully",
			setup: func() (Transformer, []byte) {
				prefixes := []PrefixTransformer{
					{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
					{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
				}
				union := NewPrefixTransformers(fmt.Errorf("default"), prefixes...)
				return union, []byte("v1:data")
			},
			expectedToSucceed: true,
		},
		{
			name: "happy path second",
			desc: "data with second transformer prefix decrypts successfully",
			setup: func() (Transformer, []byte) {
				prefixes := []PrefixTransformer{
					{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
					{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
				}
				union := NewPrefixTransformers(fmt.Errorf("default"), prefixes...)
				return union, []byte("v2:data")
			},
			expectedToSucceed: true,
		},
		{
			name: "no prefix match",
			desc: "data with unknown prefix fails",
			setup: func() (Transformer, []byte) {
				prefixes := []PrefixTransformer{
					{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
					{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
				}
				union := NewPrefixTransformers(fmt.Errorf("no matching transformer"), prefixes...)
				return union, []byte("v3:data")
			},
			expectedToSucceed: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer, data := tt.setup()
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

			_, _, err := transformer.TransformFromStorage(ctx, data, nil)

			if tt.expectedToSucceed && err != nil {
				t.Errorf("test %q: %s - expected success but got error: %v", tt.name, tt.desc, err)
			}
			if !tt.expectedToSucceed && err == nil {
				t.Errorf("test %q: %s - expected error but got success", tt.name, tt.desc)
			}
		})
	}
}

// TestContextDataPreservation tests that Context properly preserves data through the transformation process
func TestContextDataPreservation(t *testing.T) {
	tests := []struct {
		name         string
		contextData  []byte
		transformData []byte
	}{
		{
			name:         "simple context data",
			contextData:  []byte("context-key-123"),
			transformData: []byte("secret"),
		},
		{
			name:         "empty context data",
			contextData:  []byte(""),
			transformData: []byte("secret"),
		},
		{
			name:         "binary context data",
			contextData:  []byte{0, 1, 2, 255},
			transformData: []byte("secret"),
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx := DefaultContext(tt.contextData)
			transformer := &mockTransformer{encryptPrefix: []byte("v1:")}
			appCtx := context.Background()

			// Verify context data is accessible
			if !bytes.Equal(ctx.AuthenticatedData(), tt.contextData) {
				t.Errorf("context data not preserved")
			}

			// Verify transformation works with context
			encrypted, err := transformer.TransformToStorage(appCtx, tt.transformData, ctx)
			if err != nil {
				t.Errorf("transformation with context failed: %v", err)
			}

			if len(encrypted) == 0 {
				t.Errorf("encrypted data should not be empty")
			}
		})
	}
}

// TestTransformerErrorHandlingTableDriven tests various error scenarios in a table-driven format
func TestTransformerErrorHandlingTableDriven(t *testing.T) {
	type transformError struct {
		name          string
		data          []byte
		shouldFail    bool
		failOnFrom    bool
		failOnTo      bool
		expectedError string
	}

	tests := []transformError{
		{
			name:          "nil data with error",
			data:          []byte("test"),
			shouldFail:    true,
			failOnFrom:    true,
			failOnTo:      false,
			expectedError: "mock decrypt error",
		},
		{
			name:          "encrypt failure",
			data:          []byte("test"),
			shouldFail:    true,
			failOnFrom:    false,
			failOnTo:      true,
			expectedError: "mock encrypt error",
		},
		{
			name:          "both operations fail",
			data:          []byte("test"),
			shouldFail:    true,
			failOnFrom:    true,
			failOnTo:      true,
			expectedError: "mock encrypt error",
		},
		{
			name:       "no error",
			data:       []byte("test"),
			shouldFail: false,
		},
	}

	ctx := context.Background()

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &mockTransformer{
				encryptPrefix: []byte("v1:"),
				failOnFrom:    tt.failOnFrom,
				failOnTo:      tt.failOnTo,
			}

			// Test encryption error
			if tt.failOnTo {
				_, err := transformer.TransformToStorage(ctx, tt.data, nil)
				if err == nil {
					t.Errorf("expected encryption error but got none")
				}
				if !bytes.Contains([]byte(err.Error()), []byte(tt.expectedError)) {
					t.Errorf("error message mismatch. expected: %s, got: %v", tt.expectedError, err)
				}
				return
			}

			// Test decryption error
			encrypted, err := transformer.TransformToStorage(ctx, tt.data, nil)
			if err != nil && !tt.shouldFail {
				t.Fatalf("encryption should not fail: %v", err)
			}

			if tt.failOnFrom {
				_, _, err := transformer.TransformFromStorage(ctx, encrypted, nil)
				if err == nil {
					t.Errorf("expected decryption error but got none")
				}
			}
		})
	}
}

