		inputData         []byte
		shouldFail        bool
		expectedToFail    error
		expectedStale     bool
	}{
		{
			name: "first transformer matches",
			prefixTransformers: []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
				{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
			},
			inputData:      []byte("v1:secret"),
			shouldFail:     false,
			expectedStale:  false,
		},
		{
			name: "second transformer matches",
			prefixTransformers: []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
				{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
			},
			inputData:      []byte("v2:secret"),
			shouldFail:     false,
			expectedStale:  true, // Should be marked stale since it's not the first transformer
		},
		{
			name: "no transformer matches",
			prefixTransformers: []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &mockTransformer{encryptPrefix: []byte("v1:")}},
				{Prefix: []byte("v2:"), Transformer: &mockTransformer{encryptPrefix: []byte("v2:")}},
